23	// US-051 — Create-campaign wizard step 3 (post-conditions). Free-text rules the
24	// creator will self-affirm at submit time (docs/product-plan.md §3.1). Each row
25	// gets a stable RFC-4122 v4 UUID so the submission flow (US-045 / US-046) can
26	// map per-rule affirmations back to their source rule, and so the publish step
27	// can write them as `listing_conditions` rows with `condition_kind='post'`
28	// without a server-side re-mint.
29	//
30	// Rows are stored in the wizard draft (AsyncStorage-backed, see WizardStore).
31	// Post-conditions are optional — an empty list is a valid "no content rules"
32	// listing, matching step-2's posture for pre-conditions. Next is always enabled.
33	
34	// Simple RFC-4122 v4 generator — Math.random is adequate for wizard-local ids
35	// (no security boundary; the server re-validates at publish). Avoids adding an
36	// `expo-crypto` dep just for this one call site.
37	function makeUuid(): string {
38	  const bytes = new Array<number>(16);
39	  for (let i = 0; i < 16; i++) bytes[i] = Math.floor(Math.random() * 256);
40	  bytes[6] = (bytes[6] & 0x0f) | 0x40;
41	  bytes[8] = (bytes[8] & 0x3f) | 0x80;
42	  const hex = bytes.map((b) => b.toString(16).padStart(2, '0')).join('');
43	  return `${hex.slice(0, 8)}-${hex.slice(8, 12)}-${hex.slice(12, 16)}-${hex.slice(16, 20)}-${hex.slice(20, 32)}`;
44	}
