82	    <SafeAreaView style={styles.root}>
83	      <KeyboardAvoidingView
84	        style={styles.flex}
85	        behavior={Platform.OS === 'ios' ? 'padding' : undefined}
86	      >
87	        <ScrollView
88	          contentContainerStyle={styles.scroll}
89	          keyboardShouldPersistTaps="handled"
90	        >
91	          <View style={styles.header}>
92	            <Pressable
93	              onPress={onBack}
94	              hitSlop={{ top: 12, bottom: 12, left: 12, right: 12 }}
95	              accessibilityRole="button"
96	              accessibilityLabel="Back"
97	              testID="wizard-step3-back"
98	              style={styles.backBtn}
99	            >
100	              <ChevronLeft size={24} color={colors.ink} />
101	            </Pressable>
102	            <Text style={[textStyles.micro, styles.stepLabel]} allowFontScaling={false}>
103	              Step 3 of 5
104	            </Text>
105	            <Text style={[textStyles.display, styles.title]} maxFontSizeMultiplier={1.3}>
106	              Content rules
107	            </Text>
108	            <Text style={[textStyles.body, styles.subtitle]} maxFontSizeMultiplier={1.3}>
109	              Rules creators must self-affirm before submitting. Leave empty to set no rules.
110	            </Text>
