59	export default function CampaignWizardStep2() {
60	  const { draft, updateField } = useWizard();
61	
62	  // All three mutations use `updateField`'s functional updater so rapid-fire
63	  // taps (e.g. "Add condition" pressed twice before a re-render) read the
64	  // latest array rather than the closure-captured snapshot.
65	  const onAddRow = useCallback(() => {
66	    const row: WizardPreCondition = {
67	      id: makeLocalId(),
68	      platform: 'tiktok',
69	      metric: 'followers',
70	      threshold: 0,
71	    };
72	    updateField('preConditions', (prev) => [...prev, row]);
73	  }, [updateField]);
74	
75	  const onRemoveRow = useCallback(
76	    (id: string) => {
77	      updateField('preConditions', (prev) => prev.filter((row) => row.id !== id));
78	    },
79	    [updateField],
80	  );
81	
82	  const onUpdateRow = useCallback(
83	    (id: string, patch: Partial<Omit<WizardPreCondition, 'id'>>) => {
84	      updateField('preConditions', (prev) =>
85	        prev.map((row) => (row.id === id ? { ...row, ...patch } : row)),
86	      );
87	    },
